import{f as t,o as n,c as r,a7 as e}from"./chunks/framework.CE9Fg-de.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段18-AI与Go工程化.md","filePath":"S6-Go/阶段18-AI与Go工程化.md","lastUpdated":1780493670000}'),a={name:"S6-Go/阶段18-AI与Go工程化.md"};function s(i,o,l,g,d,p){return n(),r("div",null,[...o[0]||(o[0]=[e('<h2 id="🤖-阶段十八-ai-ml-与-go-工程化结合" tabindex="-1">🤖 阶段十八：AI/ML 与 Go 工程化结合 <a class="header-anchor" href="#🤖-阶段十八-ai-ml-与-go-工程化结合" aria-label="Permalink to &quot;🤖 阶段十八：AI/ML 与 Go 工程化结合&quot;">​</a></h2><h3 id="_18-1-模型服务化" tabindex="-1">18.1 模型服务化 <a class="header-anchor" href="#_18-1-模型服务化" aria-label="Permalink to &quot;18.1 模型服务化&quot;">​</a></h3><h4 id="q68-如何使用-go-部署和调用大语言模型-llm-api" tabindex="-1">Q68: 如何使用 Go 部署和调用大语言模型（LLM）API？ <a class="header-anchor" href="#q68-如何使用-go-部署和调用大语言模型-llm-api" aria-label="Permalink to &quot;Q68: 如何使用 Go 部署和调用大语言模型（LLM）API？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：HTTP/gRPC 调用、流式响应、Token 计算、并发控制。</p><p><strong>💡 记忆关键词</strong>：SSE 流式、Token 计算、并发控制、连接池</p><p><strong>答案要点</strong>：</p><ul><li><strong>调用方式</strong>：REST API（OpenAI 兼容格式）或 gRPC（vLLM/TensorRT-LLM）。</li><li><strong>流式处理</strong>：使用 <code>http.Response.Body</code> 逐块读取 SSE（Server-Sent Events），解析 <code>data: {...}</code>。</li><li><strong>并发控制</strong>：限制 QPS、设置超时、使用连接池；避免阻塞 Goroutine。</li><li><strong>Token 估算</strong>：使用 <code>tiktoken-go</code> 库计算输入/输出 Token 数，控制成本。</li></ul><h4 id="q69-go-如何对接向量数据库-milvus-pinecone-实现-rag-架构" tabindex="-1">Q69: Go 如何对接向量数据库（Milvus/Pinecone）实现 RAG 架构？ <a class="header-anchor" href="#q69-go-如何对接向量数据库-milvus-pinecone-实现-rag-架构" aria-label="Permalink to &quot;Q69: Go 如何对接向量数据库（Milvus/Pinecone）实现 RAG 架构？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：Embedding 生成、相似度搜索、混合检索、缓存策略。</p><p><strong>💡 记忆关键词</strong>：Embedding、ANN 搜索、HNSW、混合检索</p><p><strong>答案要点</strong>：</p><ul><li><strong>流程</strong>：文本 → Embedding 模型 → 向量入库 → 查询时生成向量 → ANN 搜索（HNSW/IVF）→ 返回 Top-K。</li><li><strong>Go 集成</strong>：使用 <code>milvus-io/milvus-sdk-go/v2</code> 或 HTTP API；批量插入、分区管理、索引构建。</li><li><strong>优化</strong>：缓存热点查询结果、使用混合检索（向量 + 关键词）、定期清理过期数据。</li></ul><h3 id="_18-2-推理优化" tabindex="-1">18.2 推理优化 <a class="header-anchor" href="#_18-2-推理优化" aria-label="Permalink to &quot;18.2 推理优化&quot;">​</a></h3><h4 id="q70-go-服务中如何优化-ai-推理延迟与吞吐量" tabindex="-1">Q70: Go 服务中如何优化 AI 推理延迟与吞吐量？ <a class="header-anchor" href="#q70-go-服务中如何优化-ai-推理延迟与吞吐量" aria-label="Permalink to &quot;Q70: Go 服务中如何优化 AI 推理延迟与吞吐量？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：批处理（Batching）、模型量化、GPU 共享、异步推理。</p><p><strong>💡 记忆关键词</strong>：动态批处理、模型量化、gRPC 调用、P99 监控</p><p><strong>答案要点</strong>：</p><ul><li><strong>动态批处理</strong>：收集多个请求合并为一次推理（如 32 条/批），降低单位延迟。</li><li><strong>模型优化</strong>：使用 ONNX Runtime、TensorRT 部署量化模型（INT8/FP16）。</li><li><strong>架构设计</strong>：推理服务独立部署，Go 通过 gRPC 调用；使用消息队列削峰填谷。</li><li><strong>监控</strong>：跟踪 P99 延迟、GPU 利用率、批处理大小分布。</li></ul><hr>',22)])])}const u=t(a,[["render",s]]);export{h as __pageData,u as default};
